import argparse
import json
import pickle
import numpy as np
import torch
import warnings
from torchvision import transforms, models
from PIL import Image
from pathlib import Path
from tqdm import tqdm
import timm
from transformers import AutoModel

warnings.filterwarnings('ignore')
Image.MAX_IMAGE_PIXELS = None

T_DINO = transforms.Compose([
    transforms.Resize(224, interpolation=transforms.InterpolationMode.BICUBIC),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize([0.485,0.456,0.406],[0.229,0.224,0.225])
])
T_CLIP = transforms.Compose([
    transforms.Resize(224, interpolation=transforms.InterpolationMode.BICUBIC),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize([0.48145466,0.4578275,0.40821073],[0.26862954,0.26130258,0.27577711])
])
T_RESNET = transforms.Compose([
    transforms.Resize(256, interpolation=transforms.InterpolationMode.BILINEAR),
    transforms.CenterCrop(224),
    transforms.ToTensor(),
    transforms.Normalize([0.485,0.456,0.406],[0.229,0.224,0.225])
])

class DS(torch.utils.data.Dataset):
    def __init__(self, txt, root, tfm):
        self.r = Path(root)
        self.t = tfm
        with open(txt) as f:
            self.s = [l.strip() for l in f if l.strip()]
    def __len__(self):
        return len(self.s)
    def __getitem__(self, i):
        return self.t(Image.open(self.r / self.s[i]).convert('RGB'))

@torch.no_grad()
def ext(model, loader, device, is_vit=False):
    model.eval()
    out = []
    for x in tqdm(loader, desc='feat'):
        x = x.to(device)
        y = model(x)
        if is_vit and hasattr(y, 'last_hidden_state'):
            y = y.last_hidden_state[:, 0]
        z = model(torch.flip(x, dims=[3]))
        if is_vit and hasattr(z, 'last_hidden_state'):
            z = z.last_hidden_state[:, 0]
        out.append(((y + z) * 0.5).cpu().numpy())
    return np.concatenate(out, axis=0)

def normalize(x):
    return x / (np.linalg.norm(x, axis=1, keepdims=True) + 1e-8)

def get_dim(ck):
    if hasattr(ck, 'coef_'):
        return ck.coef_.shape[1]
    if isinstance(ck, np.ndarray):
        return ck.shape[-1]
    if isinstance(ck, list) and len(ck) > 0:
        return get_dim(ck[0])
    if isinstance(ck, dict):
        if 'prototypes' in ck:
            return ck['prototypes'].shape[-1]
        if 'clfs' in ck:
            return get_dim(ck['clfs'])
        if 'items' in ck and len(ck['items']) > 0:
            first = ck['items'][0]
            if isinstance(first, dict) and 'model' in first:
                return get_dim(first['model'])
            return get_dim(first)
    raise ValueError(f'Cannot infer dim from {type(ck)}')

def get_needed_backbones(dim_size):
    mapping = {768: {'dinov2'}, 2048: {'resnet'}, 2816: {'dinov2','resnet'}, 3584: {'dinov2','resnet','clip'}}
    if dim_size not in mapping:
        raise ValueError(f'Unknown feature dimension {dim_size}')
    return mapping[dim_size]

def predict_proba(ck, fm):
    if hasattr(ck, 'predict_proba'):
        return ck.predict_proba(fm['all'])
    if isinstance(ck, np.ndarray):
        protos = ck
        scores = np.zeros((len(fm['all']), protos.shape[1]))
        for d in range(len(protos)):
            sim = fm['all'] @ protos[d].T
            e = np.exp(sim - np.max(sim, axis=1, keepdims=True))
            scores += e / np.sum(e, axis=1, keepdims=True)
        return scores / len(protos)
    if isinstance(ck, list):
        s = np.zeros((len(fm['all']), 10))
        for c in ck:
            s += predict_proba(c, fm)
        return s / len(ck)
    if isinstance(ck, dict):
        if 'prototypes' in ck:
            return predict_proba(ck['prototypes'], fm)
        if 'clfs' in ck:
            return predict_proba(ck['clfs'], fm)
        if 'items' in ck:
            total = None
            wsum = 0.0
            for item in ck['items']:
                if isinstance(item, dict) and 'weight' in item:
                    w = item['weight']
                    m = item.get('model', item)
                else:
                    w = 1.0
                    m = item
                p = predict_proba(m, fm) * w
                total = p if total is None else total + p
                wsum += w
            return total / wsum if wsum > 0 else total
    raise ValueError(f'Unsupported checkpoint type {type(ck)}')

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    args = parser.parse_args()

    dp = Path(args.data_path)
    with open(args.checkpoint, 'rb') as f:
        ck = pickle.load(f)

    dim_size = get_dim(ck)
    need = get_needed_backbones(dim_size)
    print(f'Feature dim: {dim_size}, need backbones: {need}')

    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    img_root = dp / 'images'
    txt_path = dp / 'test.txt'
    with open(txt_path) as f:
        lines = [l.strip() for l in f if l.strip()]
    print(f'Test samples: {len(lines)}')

    feat_dict = {}
    if 'dinov2' in need:
        print('Loading DINOv2...')
        dino = AutoModel.from_pretrained('facebook/dinov2-base').to(device).eval()
        ds = DS(txt_path, img_root, T_DINO)
        dl = torch.utils.data.DataLoader(ds, batch_size=64, shuffle=False, num_workers=4, pin_memory=True)
        feat_dict['dinov2'] = normalize(ext(dino, dl, device, is_vit=True))
        del dino
        torch.cuda.empty_cache()

    if 'resnet' in need:
        print('Loading ResNet50...')
        resnet = models.resnet50(weights='IMAGENET1K_V2').to(device).eval()
        resnet.fc = torch.nn.Identity()
        ds = DS(txt_path, img_root, T_RESNET)
        dl = torch.utils.data.DataLoader(ds, batch_size=64, shuffle=False, num_workers=4, pin_memory=True)
        feat_dict['resnet'] = normalize(ext(resnet, dl, device))
        del resnet
        torch.cuda.empty_cache()

    if 'clip' in need:
        print('Loading CLIP ViT...')
        clip_model = timm.create_model('vit_base_patch16_clip_224.openai', pretrained=True, num_classes=0).to(device).eval()
        ds = DS(txt_path, img_root, T_CLIP)
        dl = torch.utils.data.DataLoader(ds, batch_size=64, shuffle=False, num_workers=4, pin_memory=True)
        feat_dict['clip'] = normalize(ext(clip_model, dl, device))
        del clip_model
        torch.cuda.empty_cache()

    parts = []
    for k in ['dinov2', 'resnet', 'clip']:
        if k in feat_dict:
            parts.append(feat_dict[k])
    fm = {'all': np.concatenate(parts, axis=1)}
    fm.update(feat_dict)
    print(f'Feature matrix shape: {fm["all"].shape}')

    probs = predict_proba(ck, fm)
    preds = np.argmax(probs, axis=1).tolist()

    with open(args.output, 'w') as f:
        json.dump({'predictions': preds}, f)
    print(f'Wrote {args.output}')

if __name__ == '__main__':
    main()
